import { useEffect, type DependencyList, type RefObject } from 'react';

const MESSAGE_TEXT_SELECTOR = '[class*="messageText"]';

function syncLinesGridMessageTitles(root: HTMLElement): void {
  root.querySelectorAll<HTMLElement>(MESSAGE_TEXT_SELECTOR).forEach(el => {
    const text = el.textContent?.trim() ?? '';
    const truncated = el.scrollHeight > el.clientHeight + 1;
    if (truncated && text) {
      el.setAttribute('title', text);
    } else {
      el.removeAttribute('title');
    }
  });
}

/** Tooltip (native title) khi error/help trong linesTable bị cắt sau line-clamp. */
export function useLinesGridMessageTitles(
  sectionRef: RefObject<HTMLElement | null>,
  deps: DependencyList,
): void {
  useEffect(() => {
    const root = sectionRef.current;
    if (!root) return undefined;

    const sync = () => syncLinesGridMessageTitles(root);

    sync();
    const mutationObserver = new MutationObserver(sync);
    mutationObserver.observe(root, {
      subtree: true,
      childList: true,
      characterData: true,
      attributes: true,
    });
    const resizeObserver = new ResizeObserver(sync);
    resizeObserver.observe(root);

    return () => {
      mutationObserver.disconnect();
      resizeObserver.disconnect();
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps -- re-sync when line errors / labels change
  }, deps);
}
